 function parseTranslation(json) {
			   var rootArray = JSON.parse(json);
			   var totalText = "";

			   for(var i = 0; i < rootArray[0].length; i++) {
				  var text = rootArray[0][i][0];
				  totalText = totalText + text;
			   }
			   return totalText;
		   }

function getSuggestedPhotos(html, limit, thresholdSize) {
               var contentTag = document.createElement('div');
               contentTag.innerHTML = html;
               const scripts = contentTag.querySelectorAll("script");
               const regex = /data:image\/jpeg;base64,([^\\']+)/;
               var resultImages = []
               var resultBase64 = []
               for (var i = 0; i < scripts.length; i++) {
                   const content = scripts[i].innerHTML;
                   const match = regex.exec(content);
                   if (match && match[1]) {
                     const data = "base64," + match[1];
                     resultBase64.push(data);
                   }
               }
               resultBase64.sort((a, b) => b.length - a.length);
               for (var i = 0; i < resultBase64.length; i++){
                   resultImages.push({base64: resultBase64[i], width: 0, height: 0, url: ""})
               }
               return JSON.stringify(resultImages)
           }

function getSuggestedPhotos(html, limit, thresholdSize) {
               var contentTag = document.createElement('div');
               contentTag.innerHTML = html;
               var imageList = contentTag.querySelectorAll("img");
               var resultImages = []
               for (var i = 0; i < imageList.length; i++) {
                   var image = imageList[i]
                   if ((!image.hasAttribute("width") || !image.hasAttribute("height")) || (image.width >= thresholdSize && image.height >= thresholdSize)) {
                       var base64 = "";
                       var url = "";
                       var src = "";
                       //get correct src
                       if (image.src) {
                           src = image.src
                       } else if (image.getAttribute("data-src")) {
                           src = image.getAttribute("data-src")
                       } else {
                           continue;
                       }
                       //check base64 or url
                       if (src.match("^http")) {
                           url = src
                       } else if (src.match("^data:image")) {
                           base64 = src
                       } else {
                           continue;
                       }
                       resultImages.push({base64: base64, width: image.width, height: image.height, url: url})
                       if (resultImages.length >= limit) {
                           break;
                       }
                   }
               }
               return JSON.stringify(resultImages)
           }

